content:
{
  "sentences": [
    {
      "text": "我不會說中文，可是我想慢慢學。",
      "pinyin": "Wǒ bù huì shuō Zhōngwén, kěshì wǒ xiǎng mànmàn xué.",
      "pinyin_numeric": "wo3 bu4 hui4 shuo1 Zhong1wen2, ke3shi4 wo3 xiang3 man4man4 xue2.",
      "translation_en": "I can't speak Chinese, but I want to learn slowly.",
      "translation_ko": "저는 중국어를 할 줄 모르지만, 천천히 배우고 싶어요."
    },
    {
      "text": "他不太會寫字，可是已經進步很多了。",
      "pinyin": "Tā bù tài huì xiě zì, kěshì yǐjīng jìnbù hěn duō le.",
      "pinyin_numeric": "ta1 bu4 tai4 hui4 xie3 zi4, ke3shi4 yi3jing1 jin4bu4 hen3 duo1 le0.",
      "translation_en": "He's not very good at writing characters, but he has already improved a lot.",
      "translation_ko": "그는 글씨를 잘 쓰지 못하지만, 이미 많이 발전했어요."
    },
    {
      "sentence": "我完全不會開車，所以需要學。",
      "text": "我完全不會開車，所以需要學。",
      "pinyin": "Wǒ wánquán bù huì kāichē, suǒyǐ xūyào xué.",
      "pinyin_numeric": "wo3 wan2quan2 bu4 hui4 kai1che1, suo3yi3 xu1yao4 xue2.",
      "translation_en": "I can't drive at all, so I need to learn.",
      "translation_ko": "저는 운전을 전혀 할 줄 몰라서 배워야 해요."
    },
    {
      "text": "她還不太會煮菜，可是她每天努力練習。",
      "pinyin": "Tā hái bù tài huì zhǔ cài, kěshì tā měitiān nǔlì liànxí.",
      "pinyin_numeric": "ta1 hai2 bu4 tai4 hui4 zhu3 cai4, ke3shi4 ta1 mei3tian1 nu3li4 lian4xi2.",
      "translation_en": "She's still not very good at cooking, but she practices hard every day.",
      "translation_ko": "그녀는 아직 요리를 잘 못하지만, 매일 열심히 연습해요."
    },
    {
      "text": "你會不會游泳？我不會，可是我想學。",
      "pinyin": "Nǐ huì bù huì yóuyǒng? Wǒ bù huì, kěshì wǒ xiǎng xué.",
      "pinyin_numeric": "ni3 hui4 bu4 hui4 you2yong3? wo3 bu4 hui4, ke3shi4 wo3 xiang3 xue2.",
      "translation_en": "Can you swim? I can't, but I want to learn.",
      "translation_ko": "수영할 줄 아세요? 저는 못 하지만 배우고 싶어요."
    },
    {
      "text": "他不會唱歌，可是他很喜歡聽音樂。",
      "pinyin": "Tā bù huì chànggē, kěshì tā hěn xǐhuān tīng yīnyuè.",
      "pinyin_numeric": "ta1 bu4 hui4 chang4ge1, ke3shi4 ta1 hen3 xi3huan1 ting1 yin1yue4.",
      "translation_en": "He can't sing, but he really likes listening to music.",
      "translation_ko": "그는 노래를 못 하지만 음악 듣는 것을 아주 좋아해요."
    },
    {
      "text": "我已經學中文幾個月了，可是還不太會說。",
      "pinyin": "Wǒ yǐjīng xué Zhōngwén jǐ ge yuè le, kěshì hái bù tài huì shuō.",
      "pinyin_numeric": "wo3 yi3jing1 xue2 Zhong1wen2 ji3 ge0 yue4 le0, ke3shi4 hai2 bu4 tai4 hui4 shuo1.",
      "translation_en": "I've been studying Chinese for a few months, but I still can't speak it very well.",
      "translation_ko": "저는 중국어를 몇 달째 배우고 있지만, 아직 말을 잘 못해요."
    },
    {
      "text": "她不會彈鋼琴，可是她覺得鋼琴很好聽。",
      "pinyin": "Tā bù huì tán gāngqín, kěshì tā juéde gāngqín hěn hǎotīng.",
      "pinyin_numeric": "ta1 bu4 hui4 tan2 gang1qin2, ke3shi4 ta1 jue2de0 gang1qin2 hen3 hao3ting1.",
      "translation_en": "She can't play the piano, but she thinks the piano sounds beautiful.",
      "translation_ko": "그녀는 피아노를 칠 줄 모르지만, 피아노 소리가 아름답다고 생각해요."
    },
    {
      "text": "你會不會說中文？我不太會，可是我會說一點。",
      "pinyin": "Nǐ huì bù huì shuō Zhōngwén? Wǒ bù tài huì, kěshì wǒ huì shuō yīdiǎn.",
      "pinyin_numeric": "ni3 hui4 bu4 hui4 shuo1 Zhong1wen2? wo3 bu4 tai4 hui4, ke3shi4 wo3 hui4 shuo1 yi1dian3.",
      "translation_en": "Can you speak Chinese? I'm not very good at it, but I can speak a little.",
      "translation_ko": "중국어를 할 줄 아세요? 잘하지는 못하지만 조금 할 수 있어요."
    },
    {
      "text": "他不會跳舞，可是他覺得跳舞很有意思。",
      "pinyin": "Tā bù huì tiàowǔ, kěshì tā juéde tiàowǔ hěn yǒuyìsi.",
      "pinyin_numeric": "ta1 bu4 hui4 tiao4wu3, ke3shi4 ta1 jue2de0 tiao4wu3 hen3 you3yi4si1.",
      "translation_en": "He can't dance, but he thinks dancing is very interesting.",
      "translation_ko": "그는 춤을 출 줄 모르지만, 춤추는 것이 아주 재미있다고 생각해요."
    }
  ]
}
